def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    M = int(data[1])
    S = data[2]

    # dp[m][n][l] = number of strings of length m that have LCS length l with first n characters of S
    dp = [[[0] * (N + 1) for _ in range(N + 1)] for _ in range(M + 1)]
    dp[0][0][0] = 1

    for m in range(M):
        for n in range(N + 1):
            for l in range(N + 1):
                if dp[m][n][l] == 0:
                    continue
                # Try adding a new character to the string
                # Case 1: Add a character not matching S[n] (if n < N)
                count = 26
                if n < N:
                    count -= 1  # subtract 1 if the current character in S is matched
                for i in range(N + 1):
                    dp[m + 1][n][l] = (dp[m + 1][n][l] + dp[m][n][l] * count) % MOD
                # Case 2: Add a character that matches S[n], if possible
                if n < N:
                    dp[m + 1][n + 1][l + 1] = (dp[m + 1][n + 1][l + 1] + dp[m][n][l]) % MOD

    # For each k, compute the total number of strings of length M with LCS exactly k
    ans = [0] * (N + 1)
    for n in range(N + 1):
        for l in range(N + 1):
            ans[l] = (ans[l] + dp[M][n][l]) % MOD

    print(' '.join(map(str, ans)))

